9	
10	import java.util.Arrays;
11	import java.util.stream.Collectors;
12	
13	@Component
14	public class LeagueConstraintSync {
15	    private static final Logger logger = LoggerFactory.getLogger(LeagueConstraintSync.class);
16	
17	    private final JdbcTemplate jdbcTemplate;
18	
19	    public LeagueConstraintSync(JdbcTemplate jdbcTemplate) {
20	        this.jdbcTemplate = jdbcTemplate;
21	    }
22	
23	    @PostConstruct
24	    public void syncLeagueConstraints() {
25	        String allowed = Arrays.stream(League.values())
26	                .map(Enum::name)
27	                .map(value -> "'" + value + "'")
28	                .collect(Collectors.joining(", "));
29	
30	        refreshConstraint("teams", "league", "teams_league_check", allowed);
31	        refreshConstraint("games", "league", "games_league_check", allowed);
32	    }
33	
34	    private void refreshConstraint(String table, String column, String constraintName, String allowedValuesSql) {
35	        String dropSql = "ALTER TABLE " + table + " DROP CONSTRAINT IF EXISTS " + constraintName;
36	        String addSql = "ALTER TABLE " + table + " ADD CONSTRAINT " + constraintName
37	                + " CHECK (" + column + " IN (" + allowedValuesSql + "))";
38	
39	        try {
40	            jdbcTemplate.execute(dropSql);
41	            jdbcTemplate.execute(addSql);
42	            logger.info("Synchronized {} on {}", constraintName, table);
43	        } catch (Exception ex) {
44	            logger.warn("Could not synchronize {} on {}: {}", constraintName, table, ex.getMessage());
45	        }
46	    }
47	}
