1	package com.tallyo.tallyo_backend.mapper;
2	
3	import com.tallyo.tallyo_backend.entity.Game;
4	import com.tallyo.tallyo_backend.entity.GameLeader;
5	import com.tallyo.tallyo_backend.entity.GameLeaderKey;
6	import com.tallyo.tallyo_backend.entity.ScoringPlay;
7	import com.tallyo.tallyo_backend.entity.ScoringPlayKey;
8	import com.tallyo.tallyo_backend.entity.Team;
9	import com.tallyo.tallyo_backend.enums.League;
10	import com.tallyo.tallyo_backend.enums.Sport;
11	import com.tallyo.tallyo_backend.model.espn.box_score.EspnBoxscoreResponse;
12	import tools.jackson.databind.JsonNode;
13	
14	import java.util.ArrayList;
15	import java.util.List;
16	
17	/**
18	 * Extracts stat leaders and scoring plays from ESPN summary payloads.
19	 * The summary shape varies per sport: football has top-level scoringPlays,
20	 * hockey has plays (filtered on scoringPlay=true), soccer has keyEvents
21	 * (filtered on scoringPlay=true). Leaders share one nesting across sports.
22	 */
23	public class EspnSummaryDetailsMapper {
24	
25	    public List<GameLeader> toLeaders(EspnBoxscoreResponse summary, int gameId) {
26	        List<GameLeader> result = new ArrayList<>();
27	        JsonNode teamBlocks = summary.getLeaders();
28	        if (teamBlocks == null || !teamBlocks.isArray()) {
29	            return result;
30	        }
31	        for (JsonNode teamBlock : teamBlocks) {
32	            Integer teamId = intOrNull(teamBlock.path("team").path("id"));
33	            if (teamId == null) {
34	                continue;
35	            }
36	            for (JsonNode category : teamBlock.path("leaders")) {
37	                String statName = textOrNull(category.path("name"));
38	                JsonNode topLeader = category.path("leaders").path(0);
39	                if (statName == null || topLeader.isMissingNode()) {
40	                    continue;
41	                }
42	                result.add(GameLeader.builder()
43	                        .key(new GameLeaderKey(gameId, teamId, statName))
44	                        .displayName(textOrNull(category.path("displayName")))
45	                        .statValue(doubleOrNull(topLeader.path("value")))
46	                        .displayValue(textOrNull(topLeader.path("displayValue")))
47	                        .playerName(textOrNull(topLeader.path("athlete").path("fullName")))
48	                        .playerShortName(textOrNull(topLeader.path("athlete").path("shortName")))
49	                        .build());
50	            }
51	        }
52	        return result;
53	    }
54	
55	    public List<ScoringPlay> toScoringPlays(EspnBoxscoreResponse summary, League league, Game game) {
56	        List<ScoringPlay> result = new ArrayList<>();
57	        JsonNode source = scoringPlaySource(summary, league);
58	        if (source == null || !source.isArray()) {
59	            return result;
60	        }
61	        int sequence = 0;
62	        for (JsonNode play : source) {
63	            // Football payloads list only scoring plays; hockey/soccer list all
64	            // plays/events and flag the scoring ones.
65	            if (league.getSport() != Sport.FOOTBALL && !play.path("scoringPlay").asBoolean(false)) {
66	                continue;
67	            }
68	            String playId = textOrNull(play.path("id"));
69	            if (playId == null) {
70	                playId = "seq-" + sequence;
71	            }
72	            String teamId = textOrNull(play.path("team").path("id"));
73	            result.add(ScoringPlay.builder()
74	                    .key(new ScoringPlayKey(game.getId(), playId))
75	                    .teamId(teamId)
76	                    .teamAbbreviation(resolveTeamAbbreviation(play, teamId, game))
77	                    .displayText(textOrNull(play.path("text")))
78	                    .homeScore(intOrNull(play.path("homeScore")))
79	                    .awayScore(intOrNull(play.path("awayScore")))
80	                    .scoringType(resolveScoringType(play))
81	                    .period(intOrNull(play.path("period").path("number")))
82	                    .clock(textOrNull(play.path("clock").path("displayValue")))
83	                    .sequence(sequence++)
84	                    .build());
85	        }
86	        return result;
87	    }
88	
89	    private JsonNode scoringPlaySource(EspnBoxscoreResponse summary, League league) {
90	        return switch (league.getSport()) {
91	            case FOOTBALL -> summary.getScoringPlays();
92	            case HOCKEY -> summary.getPlays();
93	            case SOCCER -> summary.getKeyEvents();
94	        };
95	    }
96	
97	    private String resolveScoringType(JsonNode play) {
98	        String fromScoringType = textOrNull(play.path("scoringType").path("abbreviation"));
99	        if (fromScoringType != null) {
100	            return fromScoringType;
101	        }
102	        String fromTypeAbbreviation = textOrNull(play.path("type").path("abbreviation"));
103	        if (fromTypeAbbreviation != null) {
104	            return fromTypeAbbreviation;
105	        }
106	        return textOrNull(play.path("type").path("text"));
107	    }
108	
109	    private String resolveTeamAbbreviation(JsonNode play, String teamId, Game game) {
110	        String fromPlay = textOrNull(play.path("team").path("abbreviation"));
111	        if (fromPlay != null) {
112	            return fromPlay;
113	        }
114	        if (teamId == null) {
115	            return null;
116	        }
117	        Team home = game.getHomeTeam();
118	        if (home != null && home.getTeamKey() != null
119	                && teamId.equals(String.valueOf(home.getTeamKey().getTeamId()))) {
120	            return home.getAbbreviation();
121	        }
122	        Team away = game.getAwayTeam();
123	        if (away != null && away.getTeamKey() != null
124	                && teamId.equals(String.valueOf(away.getTeamKey().getTeamId()))) {
125	            return away.getAbbreviation();
126	        }
127	        return null;
128	    }
129	
130	    private String textOrNull(JsonNode node) {
131	        if (node.isMissingNode() || node.isNull() || !node.isValueNode()) {
132	            return null;
133	        }
134	        String text = node.asText();
135	        return text.isEmpty() ? null : text;
136	    }
137	
138	    private Integer intOrNull(JsonNode node) {
139	        if (node.isMissingNode() || node.isNull() || !node.isValueNode()) {
140	            return null;
141	        }
142	        if (node.isNumber()) {
143	            return node.asInt();
144	        }
145	        try {
146	            return Integer.parseInt(node.asText().trim());
147	        } catch (NumberFormatException e) {
148	            return null;
149	        }
150	    }
151	
152	    private Double doubleOrNull(JsonNode node) {
153	        if (node.isMissingNode() || node.isNull() || !node.isNumber()) {
154	            return null;
155	        }
156	        return node.asDouble();
157	    }
158	}
