420	  const [sortByScope, setSortByScope] = useState<
421	    Record<string, { columnId: string; direction: SortDirection }>
422	  >({});
423	
424	  const toggleOpenStandings = (id: string) => {
425	    setOpenStandings((prev) => ({ ...prev, [id]: !prev[id] }));
426	  };
427	
428	  const getSortState = (scopeKey: string) => sortByScope[scopeKey] ?? null;
429	
430	  const toggleSort = (columnId: string, scopeKey: string) => {
431	    setSortByScope((prev) => {
432	      const current = prev[scopeKey];
433	      const next = { ...prev };
434	      if (!current || current.columnId !== columnId) {
435	        next[scopeKey] = { columnId, direction: "desc" };
436	        return next;
437	      }
438	      if (current.direction === "desc") {
439	        next[scopeKey] = { columnId, direction: "asc" };
440	        return next;
441	      }
442	      delete next[scopeKey];
443	      return next;
444	    });
445	  };
446	
447	  const getSortedRows = (rows: StandingsRow[], scopeKey: string) => {
448	    const sortState = getSortState(scopeKey);
