452	
453	    const sortColumn = profile.columns.find(
454	      (col) => col.id === sortState.columnId,
455	    );
456	    if (!sortColumn?.sortValue) {
457	      return rows;
458	    }
459	
460	    const sorted = [...rows].sort((a, b) => {
461	      const aValue = sortColumn.sortValue!(a.team);
462	      const bValue = sortColumn.sortValue!(b.team);
463	      if (typeof aValue === "number" && typeof bValue === "number") {
464	        return aValue - bValue;
465	      }
466	      return String(aValue).localeCompare(String(bValue));
467	    });
468	
469	    return sortState.direction === "desc" ? sorted.reverse() : sorted;
470	  };
