const { chromium } = require("playwright");

(async () => {
  const browser = await chromium.launch();
  const page = await browser.newPage({ viewport: { width: 1200, height: 900 } });
  page.on("console", (m) => m.type() === "error" && console.log("console error:", m.text()));
  await page.goto("http://localhost:3300/world_cup", { waitUntil: "networkidle", timeout: 60000 });

  await page.getByText("World Cup Standings").first().click();
  await page.getByText("Group A", { exact: true }).first().click();
  await page.getByText("Group B", { exact: true }).first().click();
  await page.waitForTimeout(500);

  const el = await page.getByText("World Cup Standings").first().locator("xpath=ancestor::div[contains(@class,'divide-x')]");
  await el.screenshot({ path: "standings.png" });
  await page.screenshot({ path: "page.png", fullPage: false });
  await browser.close();
  console.log("screenshots saved");
})();

const { chromium } = require("playwright");

